def _safe_get(d: dict, key: str, default=None):
    """
    Return d[key] if present and not None, else default.
    Treats explicit None as "missing" so callers that pass defaults get them.
    """
    if not isinstance(d, dict):
        return default
    # Use get but treat None as missing
    v = d.get(key, None)
    if v is None:
        return default
    return v

def _coerce_number(v, default=0.0):
    try:
        return float(v)
    except Exception:
        try:
            return float(str(v).strip())
        except Exception:
            return default
def _coerce_int(v, default=0):
    try: return int(v)
    except Exception: return default
def _coerce_bool(v, default=False):
    if v is None: return default
    if isinstance(v, bool): return v
    s=str(v).strip().lower()
    if s in ('1','true','yes','y','t'): return True
    if s in ('0','false','no','n','f'): return False
    return default
def _json_safe_load(s):
    if s is None: return None
    if isinstance(s,(dict,list)): return s
    try: return json.loads(s)
    except Exception: return None
def _repr(v, maxlen=60):
    try:
        s = json.dumps(v, ensure_ascii=False)
    except Exception:
        s = str(v)
    if len(s)>maxlen: return s[:maxlen-1]+'…'
    return s

