@register('cond_compare')
def cond_compare(inputs, params):
    a = _safe_get(inputs,'A',None)
    b = _safe_get(inputs,'B',None)
    op = params.get('op','==')
    try:
        if op in ('==','equals'):
            r = (str(a)==str(b))
        elif op in ('!=','<>'):
            r = (str(a)!=str(b))
        else:
            # best-effort numeric compare
            ra = _coerce_number(a, None)
            rb = _coerce_number(b, None)
            if ra is None or rb is None:
                r = False
            else:
                if op == '>': r = ra > rb
                elif op == '<': r = ra < rb
                elif op == '>=': r = ra >= rb
                elif op == '<=': r = ra <= rb
                else:
                    r = False
    except Exception:
        r = False
    return {'Résultat': r}

@register('cond_filter')
def cond_filter(inputs, params):
    lst = _safe_get(inputs,'Liste', [])
    pred = params.get('predicate')
    if not isinstance(lst, list): lst = [lst]
    if not pred:
        return {'Liste': lst, 'Nb': len(lst)}
    try:
        out = [x for x in lst if eval(pred, {}, {'x': x})]
        return {'Liste': out, 'Nb': len(out)}
    except Exception as e:
        return {'Liste': None, 'Erreur': str(e)}

