@register('action_write_file')
def action_write_file(inputs, params):
    path = _safe_get(inputs, 'Chemin', params.get('path', None))
    content = _safe_get(inputs, 'Contenu', params.get('content', ''))
    # If content is None, write empty string
    if content is None:
        content = ""
    mode_param = params.get('mode', 'Écraser')
    encoding = params.get('encoding', 'UTF-8') or 'UTF-8'
    create_dirs = _coerce_bool(params.get('create_dirs', True), True)

    if isinstance(path, str) and path.strip().lower() == "none":
        path = None
    if not path:
        return {'Succès': False, 'Erreur': 'No path'}

    try:
        d = os.path.dirname(path)
        if d and create_dirs and not os.path.exists(d):
            os.makedirs(d, exist_ok=True)

        if mode_param == 'Ajouter':
            open_mode = 'a'
        elif mode_param == 'Créer uniquement':
            if os.path.exists(path):
                return {'Succès': False, 'Erreur': 'File exists'}
            open_mode = 'w'
        else:
            open_mode = 'w'

        with open(path, open_mode, encoding=encoding) as fh:
            fh.write(str(content))
        return {'Succès': True}
    except PermissionError as pe:
        return {'Succès': False, 'Erreur': f'Permission denied: {pe}'}
    except Exception as e:
        return {'Succès': False, 'Erreur': str(e)}

