@register('action_http')
def action_http(inputs, params):
    """
    HTTP request node backend using urllib (no external deps)

    Inputs possibles:
        URL
        Body

    Params possibles:
        method   -> GET / POST / PUT / PATCH / DELETE
        headers  -> JSON string ou dict
        timeout  -> seconds
    """

    import urllib.request
    import urllib.error
    import urllib.parse
    import json

    url = _safe_get(inputs, "URL", params.get("url"))
    body = _safe_get(inputs, "Body", params.get("body"))
    method = str(params.get("method", "GET")).upper()
    timeout = float(params.get("timeout", 30))

    # headers peuvent être JSON string
    headers = params.get("headers", {})
    if isinstance(headers, str):
        try:
            headers = json.loads(headers)
        except Exception:
            headers = {}

    if not url:
        return {"Succès": False, "Erreur": "URL manquante"}

    try:
        data = None

        if method in ("POST", "PUT", "PATCH", "DELETE"):
            if isinstance(body, (dict, list)):
                data = json.dumps(body).encode("utf-8")
                headers.setdefault("Content-Type", "application/json")
            elif body is not None:
                data = str(body).encode("utf-8")

        req = urllib.request.Request(
            url=url,
            data=data,
            headers=headers,
            method=method
        )

        with urllib.request.urlopen(req, timeout=timeout) as resp:
            status = resp.getcode()
            raw = resp.read()

            try:
                text = raw.decode("utf-8")
            except:
                text = raw.decode("latin-1", errors="ignore")

        return {
            "Succès": True,
            "Code": status,
            "Réponse": text
        }

    except urllib.error.HTTPError as e:
        return {
            "Succès": False,
            "Code": e.code,
            "Erreur": str(e)
        }

    except urllib.error.URLError as e:
        return {
            "Succès": False,
            "Erreur": str(e.reason)
        }

    except Exception as e:
        return {
            "Succès": False,
            "Erreur": str(e)
        }

